require_once __DIR__.'/functions.php';if($_SERVER['REQUEST_METHOD']!=='POST'){http_response_code(405);exit;}verify_csrf();$member=require_member();$postId=filter_input(INPUT_POST,'post_id',FILTER_VALIDATE_INT);$reaction=filter_input(INPUT_POST,'reaction',FILTER_VALIDATE_INT);if(!$postId||!in_array($reaction,[-1,1],true)){http_response_code(400);exit('Reacción inválida.');}$stmt=db()->prepare('SELECT reaction FROM post_reactions WHERE post_id=? AND member_id=?');$stmt->execute([$postId,$member['id']]);$current=(int)($stmt->fetchColumn()?:0);if($current===$reaction){db()->prepare('DELETE FROM post_reactions WHERE post_id=? AND member_id=?')->execute([$postId,$member['id']]);}else{db()->prepare('INSERT INTO post_reactions(post_id,member_id,reaction) VALUES(?,?,?) ON DUPLICATE KEY UPDATE reaction=VALUES(reaction),updated_at=NOW()')->execute([$postId,$member['id'],$reaction]);}$stmt=db()->prepare('SELECT slug FROM posts WHERE id=?');$stmt->execute([$postId]);redirect('/'.rawurlencode((string)$stmt->fetchColumn()));
